Review this code for memory issues:

```typescript
class GameScene extends cc.Scene {
    onEnter() {
        super.onEnter();
        this.schedule(() => {
            const explosion = new cc.Sprite('explosion.png');
            explosion.setPosition(Math.random() * 480, Math.random() * 320);
            this.addChild(explosion);
        }, 0.1);
    }
}
```

output:
**Critical issue:** Sprites are created every 0.1 seconds but never removed. This is a memory leak — the scene accumulates 10 sprites per second indefinitely. After 60 seconds, 600 sprites exist.

**Fix:** Remove sprites after they're done, or pool them:

```typescript
class GameScene extends cc.Scene {
    onEnter() {
        super.onEnter();
        this.schedule(() => {
            const explosion = new cc.Sprite('explosion.png');
            explosion.setPosition(Math.random() * 480, Math.random() * 320);
            this.addChild(explosion);
            explosion.runAction(cc.sequence(
                cc.fadeOut(0.5),
                cc.removeSelf()
            ));
        }, 0.1);
    }
}
```

instruction:
Review this code:

```typescript
const children = node.getChildren();
for (let i = 0; i < children.length; i++) {
    node.removeChild(children[i]);
}
```

output:
**Issue:** Removing children while iterating over the children array causes index shifting. After removing child[0], child[1] becomes child[0], so the loop skips every other child.

**Fix:** Use `removeAllChildren` or iterate in reverse:

```typescript
// Option 1: Remove all (simplest)
node.removeAllChildren(true);

// Option 2: Reverse iteration
const children = node.getChildren().slice(); // copy the array
for (let i = children.length - 1; i >= 0; i--) {
    node.removeChild(children[i]);
}

// Option 3: Copy array first
const copy = [...node.getChildren()];
copy.forEach(child => node.removeChild(child));
```

instruction:
Review this scheduling code:

```typescript
class MyNode extends cc.Node {
    onEnter() {
        super.onEnter();
        this.schedule(this.tick, 1.0);
        this.schedule(this.tick, 2.0);
    }
    tick(dt: number) {
        cc.log('tick');
    }
}
```

output:
**Issue:** Scheduling the same callback (`this.tick`) twice replaces the first schedule. The second `schedule` call with interval 2.0 overrides the first one with interval 1.0. Only the 2-second interval will work.

**Fix:** Use different callbacks or use `key` parameter:

```typescript
class MyNode extends cc.Node {
    onEnter() {
        super.onEnter();
        this.schedule(this.fastTick, 1.0);
        this.schedule(this.slowTick, 2.0);
    }
    fastTick(dt: number) { cc.log('fast tick'); }
    slowTick(dt: number) { cc.log('slow tick'); }
}
```

Or use anonymous functions with keys:
```typescript
this.schedule((dt) => cc.log('fast'), 1.0, cc.macro.REPEAT_FOREVER, 0, 'fast');
this.schedule((dt) => cc.log('slow'), 2.0, cc.macro.REPEAT_FOREVER, 0, 'slow');
```

These three methods return position in different coordinate systems:

**`getPosition()`** — Returns position in **parent's local space** (pixels):
```typescript
node.setPosition(100, 200);
const pos = node.getPosition(); // cc.Point {x: 100, y: 200}
```

**`getNormalizedPosition()`** — Returns position as a **fraction (0-1) of parent size**:
```typescript
// If parent is 480x320 and node is at (240, 160)
const norm = node.getNormalizedPosition(); // cc.Point {x: 0.5, y: 0.5}
```

**`convertToWorldSpace(cc.p(0,0))`** — Returns the node's origin in **world/screen coordinates**. Note: there is no `getWorldPosition()` on cc.Node directly; you use coordinate conversion:
```typescript
const worldOrigin = node.convertToWorldSpace(cc.p(0, 0));
// Or anchor-relative:
const worldCenter = node.convertToWorldSpaceAR(cc.p(0, 0));
```

Use `getPosition` for scene graph positioning, `getNormalizedPosition` for resolution-independent layouts, and world space conversion for cross-node comparisons.

Use scheduling to spawn bullets and actions to move them:

```typescript
class Turret extends cc.Sprite {
    private bulletSpeed = 400;

    onEnter(): void {
        super.onEnter();
        this.schedule(this.fireBullet, 0.5);
    }

    fireBullet(dt: number): void {
        const bullet = new cc.Sprite('bullet.png');
        bullet.setPosition(this.getPosition());
        bullet.setScale(0.5);
        this.getParent().addChild(bullet, -1);

        const targetY = cc.director.getWinSize().height + 20;
        const dist = targetY - bullet.y;
        const duration = dist / this.bulletSpeed;

        bullet.runAction(cc.sequence(
            cc.moveTo(duration, cc.p(bullet.x, targetY)),
            cc.removeSelf()
        ));
    }

    onExit(): void {
        this.unscheduleAllCallbacks();
        super.onExit();
    }
}
```

Track touch offset and move the node accordingly:

```typescript
function makeDraggable(node: cc.Node): void {
    let dragOffset = cc.p(0, 0);

    const listener = cc.EventListener.create({
        event: cc.EventListener.TOUCH_ONE_BY_ONE,
        swallowTouches: true,
        onTouchBegan: (touch: cc.Touch, event: cc.Event): boolean => {
            const localPt = node.convertTouchToNodeSpace(touch);
            const rect = cc.rect(0, 0, node.width, node.height);
            if (cc.rectContainsPoint(rect, localPt)) {
                const worldPt = touch.getLocation();
                dragOffset = cc.p(node.x - worldPt.x, node.y - worldPt.y);
                return true;
            }
            return false;
        },
        onTouchMoved: (touch: cc.Touch, event: cc.Event): void => {
            const worldPt = touch.getLocation();
            node.setPosition(worldPt.x + dragOffset.x, worldPt.y + dragOffset.y);
        },
        onTouchEnded: (touch: cc.Touch, event: cc.Event): void => {
            cc.log('Dropped at: ' + node.x + ', ' + node.y);
        }
    });

    cc.eventManager.addListener(listener, node);
}

const card = new cc.Sprite('card.png');
card.setPosition(240, 160);
this.addChild(card);
makeDraggable(card);
```

Spawn multiple child sprites that fly outward and fade:

```typescript
function createExplosion(parent: cc.Node, pos: cc.Point, count: number): void {
    for (let i = 0; i < count; i++) {
        const particle = new cc.Sprite('spark.png');
        particle.setPosition(pos);
        particle.setScale(0.3 + Math.random() * 0.4);
        particle.setOpacity(255);
        parent.addChild(particle, 100);

        const angle = (i / count) * Math.PI * 2 + Math.random() * 0.5;
        const speed = 80 + Math.random() * 120;
        const dx = Math.cos(angle) * speed;
        const dy = Math.sin(angle) * speed;
        const duration = 0.5 + Math.random() * 0.5;

        particle.runAction(cc.sequence(
            cc.spawn(
                cc.moveBy(duration, cc.p(dx, dy)).easing(cc.easeOut(2)),
                cc.fadeOut(duration),
                cc.scaleTo(duration, 0.1)
            ),
            cc.removeSelf()
        ));
    }
}

// Usage:
createExplosion(this, cc.p(200, 200), 20);
```

Use `attr` to set all properties in one call:

```typescript
const sprite = new cc.Sprite('player.png');
sprite.attr({
    x: 240,
    y: 160,
    anchorX: 0.5,
    anchorY: 0,
    scale: 1.2,
    opacity: 200,
    rotation: 15,
    tag: 1,
    zIndex: 5
});
this.addChild(sprite);

// Combine with actions
sprite.runAction(cc.sequence(
    cc.fadeIn(0.3),
    cc.scaleTo(0.2, 1.0)
));
```

`attr` is particularly useful when creating many similar objects with slight variations:
```typescript
const configs = [
    { x: 100, y: 200, scale: 1.0 },
    { x: 200, y: 200, scale: 0.8 },
    { x: 300, y: 200, scale: 1.2 },
];
configs.forEach(cfg => {
    const s = new cc.Sprite('star.png');
    s.attr(cfg);
    this.addChild(s);
});
```

Schedule a per-frame check comparing bounding boxes:

```typescript
class GameLayer extends cc.Layer {
    private player: cc.Sprite;
    private enemies: cc.Sprite[] = [];

    onEnter(): void {
        super.onEnter();
        this.player = new cc.Sprite('hero.png');
        this.player.setPosition(240, 50);
        this.addChild(this.player);

        this.scheduleUpdate();
    }

    update(dt: number): void {
        const playerRect = this.player.getBoundingBoxToWorld();

        for (let i = this.enemies.length - 1; i >= 0; i--) {
            const enemy = this.enemies[i];
            const enemyRect = enemy.getBoundingBoxToWorld();

            if (cc.rectIntersectsRect(playerRect, enemyRect)) {
                this.onCollision(enemy);
                enemy.removeFromParent(true);
                this.enemies.splice(i, 1);
            }
        }
    }

    onCollision(enemy: cc.Sprite): void {
        cc.log('Hit enemy: ' + enemy.getName());
    }
}
```

Create a minimap node that shows scaled positions of game objects:

```typescript
class Minimap extends cc.Node {
    private gameLayer: cc.Node;
    private mapScale: number;
    private markers: Map<cc.Node, cc.Sprite> = new Map();

    constructor(gameLayer: cc.Node, mapSize: cc.Size, worldSize: cc.Size) {
        super();
        this.gameLayer = gameLayer;
        this.mapScale = mapSize.width / worldSize.width;
        this.setContentSize(mapSize);

        // Background
        const bg = new cc.DrawNode();
        bg.drawRect(cc.p(0, 0), cc.p(mapSize.width, mapSize.height),
            cc.color(0, 0, 0, 150), 1, cc.color(255, 255, 255, 100));
        this.addChild(bg);
    }

    addTracked(node: cc.Node, color: cc.Color): void {
        const marker = new cc.Sprite('dot.png');
        marker.setColor(color);
        marker.setScale(0.3);
        this.addChild(marker);
        this.markers.set(node, marker);
    }

    updatePositions(): void {
        this.markers.forEach((marker, node) => {
            const worldPos = node.convertToWorldSpace(cc.p(0, 0));
            marker.setPosition(worldPos.x * this.mapScale, worldPos.y * this.mapScale);
            marker.setVisible(node.isVisible());
        });
    }
}

// Usage
const minimap = new Minimap(this.gameLayer, cc.size(100, 75), cc.size(2000, 1500));
minimap.setPosition(370, 240);
this.addChild(minimap, 999);
minimap.addTracked(player, cc.color(0, 255, 0));
minimap.addTracked(enemy, cc.color(255, 0, 0));
// Call minimap.updatePositions() every frame
```

