output:
Implement lerp-based camera follow:

```typescript
class GameCamera extends cc.Node {
    private target: cc.Node;
    private smoothness: number = 5;
    private offset: cc.Point = cc.p(0, 0);

    setTarget(target: cc.Node): void {
        this.target = target;
    }

    setOffset(x: number, y: number): void {
        this.offset = cc.p(x, y);
    }

    onEnter(): void {
        super.onEnter();
        this.scheduleUpdate();
    }

    update(dt: number): void {
        if (!this.target) return;
        const targetPos = this.target.getPosition();
        const desiredX = targetPos.x + this.offset.x;
        const desiredY = targetPos.y + this.offset.y;
        const t = Math.min(1, this.smoothness * dt);
        this.x += (desiredX - this.x) * t;
        this.y += (desiredY - this.y) * t;
    }

    onExit(): void {
        this.unscheduleUpdate();
        super.onExit();
    }
}

