Attach behavior objects to nodes via userData:

```typescript
interface HealthComponent {
    hp: number;
    maxHp: number;
    takeDamage(amount: number): void;
    heal(amount: number): void;
    isDead(): boolean;
}

function addHealthComponent(node: cc.Node, maxHp: number): HealthComponent {
    const comp: HealthComponent = {
        hp: maxHp,
        maxHp: maxHp,
        takeDamage(amount: number): void {
            this.hp = Math.max(0, this.hp - amount);
            if (this.isDead()) {
                node.runAction(cc.sequence(
                    cc.fadeOut(0.3),
                    cc.removeSelf()
                ));
            }
        },
        heal(amount: number): void {
            this.hp = Math.min(this.maxHp, this.hp + amount);
        },
        isDead(): boolean {
            return this.hp <= 0;
        }
    };
    node.setUserData(comp);
    return comp;
}

// Usage:
const enemy = new cc.Sprite('enemy.png');
const health = addHealthComponent(enemy, 100);
health.takeDamage(30);
cc.log('HP: ' + health.hp); // 70
```

