Attach and access physics bodies on nodes:

```typescript
declare class Node {
    setPhysicsBody(body: any): void;
    getPhysicsBody(): any | null;
}
```

Usage:
```typescript
const ball = new cc.Sprite('ball.png');
ball.setPosition(240, 300);

// Create and attach a physics body
const material = new cc.PhysicsMaterial(1.0, 0.5, 0.3); // density, restitution, friction
const body = cc.PhysicsBody.createCircle(ball.width / 2, material);
body.setDynamic(true);
ball.setPhysicsBody(body);
this.addChild(ball);

// Later, access the body
const existingBody = ball.getPhysicsBody();
if (existingBody) {
    existingBody.setVelocity(cc.p(0, -200));
    existingBody.applyImpulse(cc.p(100, 0));
}
```

Note: Physics bodies require the scene to have physics world enabled. This is primarily a native (JSB) feature.

Access the event dispatcher for adding/removing listeners:

```typescript
const sprite = new cc.Sprite('interactive.png');
sprite.setPosition(240, 160);
this.addChild(sprite);

// Get the event dispatcher
const dispatcher = sprite.getEventDispatcher();
// In practice, use cc.eventManager (same global dispatcher):

const touchListener = cc.EventListener.create({
    event: cc.EventListener.TOUCH_ONE_BY_ONE,
    swallowTouches: true,
    onTouchBegan: (touch: cc.Touch, event: cc.Event): boolean => {
        const target = event.getCurrentTarget();
        const localPt = target.convertTouchToNodeSpace(touch);
        const rect = cc.rect(0, 0, target.width, target.height);
        return cc.rectContainsPoint(rect, localPt);
    },
    onTouchMoved: (touch: cc.Touch, event: cc.Event): void => {
        const target = event.getCurrentTarget();
        const delta = touch.getDelta();
        target.x += delta.x;
        target.y += delta.y;
    }
});

cc.eventManager.addListener(touchListener, sprite);
```

